/**
 * SVG Generators for PDF Charts
 * Tạo SVG strings cho các biểu đồ South Indian để convert sang Base64 cho PDF
 */

import { PdfPlanet, PdfHouse, PdfVargaPlanet } from './types';

import { LOGO_DATA_URL } from '../utils/logoDataUrl';

// South Indian chart positions (row, col) - 4x4 ';

// South Indian chart positions (row, col) - 4x4 grid
const POSITIONS = [
  [0, 1], [0, 2], [0, 3], [1, 3],
  [2, 3], [3, 3], [3, 2], [3, 1],
  [3, 0], [2, 0], [1, 0], [0, 0]
];

// Zodiac signs short names
const ZODIAC_SIGNS_SHORT = [
  "Ar", "Ta", "Ge", "Ca", "Le", "Vi",
  "Li", "Sc", "Sg", "Cp", "Aq", "Pi"
];

// Planet short names for South Indian chart
const PLANET_SHORT: Record<string, string> = {
  'Sun': 'Su', 'Moon': 'Mo', 'Mars': 'Ma', 'Mercury': 'Me',
  'Jupiter': 'Ju', 'Venus': 'Ve', 'Saturn': 'Sa',
  'Rahu': 'Ra', 'Ketu': 'Ke', 'Uranus': 'Ur', 'Neptune': 'Ne', 'Pluto': 'Pl'
};

// Colors matching PDF style
const BROWN = '#8B4513';
const BROWN_PALE = '#DEB887';
const WHITE = '#FFFFFF';
const BLACK = '#000000';

/**
 * Format degree for display
 */
function formatDegree(longitude: number): string {
  const totalDegrees = longitude % 30;
  const degrees = Math.floor(totalDegrees);
  const minutes = Math.floor((totalDegrees - degrees) * 60);
  return `${degrees}°${minutes.toString().padStart(2, '0')}'`;
}

/**
 * Get planet short name
 */
function getPlanetShort(name: string): string {
  return PLANET_SHORT[name] || name.substring(0, 2);
}

/**
 * Generate South Indian Chart SVG for Main Chart
 * Optimized to fit within border with minimal padding
 */
export function generateMainChartSVG(
  ascendant: number,
  planets: PdfPlanet[],
  houses: PdfHouse[],
  size: number = 600
): string {
  // Calculate ascendant sign
  const ascSign = Math.floor(ascendant / 30);
  const getHouseNumber = (signIndex: number) => ((signIndex - ascSign + 12) % 12) + 1;

  // Map planets to houses
  const planetsByHouse = planets.reduce((acc: Record<number, PdfPlanet[]>, planet) => {
    const houseNumber = planet.house;
    if (!acc[houseNumber]) acc[houseNumber] = [];
    acc[houseNumber].push(planet);
    return acc;
  }, {});

  // Grid settings - minimal padding for maximum fill
  const gridSize = size / 4;
  const offsetX = 0;
  const offsetY = 0;

  // Font sizes - adjusted for better spacing
  const signFontSize = size * 0.026;
  const ascFontSize = size * 0.018;
  const planetFontSize = size * 0.018;

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${size} ${size}" width="${size}" height="${size}">
    <rect x="0" y="0" width="${size}" height="${size}" fill="${WHITE}"/>
    <g transform="translate(${offsetX}, ${offsetY})">`;

  // Draw grid cells
  for (let index = 0; index < 12; index++) {
    const [row, col] = POSITIONS[index];
    const signIndex = index;
    const houseNumber = getHouseNumber(signIndex);
    const planetsInHouse = planetsByHouse[houseNumber] || [];
    const isAscendant = houseNumber === 1;

    const x = col * gridSize;
    const y = row * gridSize;

    // Cell border
    svg += `<rect x="${x}" y="${y}" width="${gridSize}" height="${gridSize}" fill="none" stroke="${BROWN}" stroke-width="2"/>`;

    // Sign name + House number - combined in one line
    svg += `<text x="${x + gridSize * 0.5}" y="${y + gridSize * 0.14}" font-size="${signFontSize}" fill="${BROWN}" font-weight="bold" font-family="Arial" text-anchor="middle">${ZODIAC_SIGNS_SHORT[signIndex]} ${houseNumber}</text>`;

    // ASC coordinates
    if (isAscendant) {
      svg += `<text x="${x + gridSize * 0.5}" y="${y + gridSize * 0.24}" font-size="${ascFontSize}" fill="${BROWN}" font-family="Arial" text-anchor="middle">ASC ${formatDegree(ascendant)}</text>`;
    }

    // Planets - with coordinates
    const planetStartY = isAscendant ? gridSize * 0.34 : gridSize * 0.28;
    planetsInHouse.slice(0, 3).forEach((planet, idx) => {
      const planetY = y + planetStartY + idx * (gridSize * 0.12);
      const suffix = planet.retrograde ? 'R' : '';
      svg += `<text x="${x + 4}" y="${planetY}" font-size="${planetFontSize}" fill="${BLACK}" font-family="Arial">${getPlanetShort(planet.name)}${suffix} ${formatDegree(planet.longitude)}</text>`;
    });
  }

  // Center - Logo image (use base64 data URI for PDF compatibility)
  const centerX = size / 2;
  const centerY = size / 2;
  const logoSize = gridSize * 0.85;
  svg += `<image href="${LOGO_DATA_URL}" x="${centerX - logoSize / 2}" y="${centerY - logoSize / 2}" width="${logoSize}" height="${logoSize}" preserveAspectRatio="xMidYMid meet"/>`;

  svg += '</g></svg>';
  return svg;
}

/**
 * Generate Mini Chart SVG for Varga Charts (compact, no overlap)
 */
export function generateMiniChartSVG(
  planets: PdfVargaPlanet[],
  ascendantSign: number,
  size: number = 200
): string {
  // Debug: show planets by house
  const debugHouses: Record<number, string> = {};
  planets.forEach(p => {
    if (!debugHouses[p.house]) debugHouses[p.house] = '';
    debugHouses[p.house] += `${p.name}(${p.vargaSign}) `;
  });
  console.log(`SVG asc=${ascendantSign}:`, JSON.stringify(debugHouses));
  
  const getHouseNumber = (signIndex: number) => ((signIndex - ascendantSign + 12) % 12) + 1;

  // Map planets to houses
  const planetsByHouse = planets.reduce((acc: Record<number, PdfVargaPlanet[]>, planet) => {
    const houseNumber = planet.house;
    if (!acc[houseNumber]) acc[houseNumber] = [];
    acc[houseNumber].push(planet);
    return acc;
  }, {});

  // Grid settings
  const gridSize = size / 4;

  let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${size} ${size}" width="${size}" height="${size}">
    <rect x="0" y="0" width="${size}" height="${size}" fill="${WHITE}"/>`;

  // Draw grid cells
  for (let index = 0; index < 12; index++) {
    const [row, col] = POSITIONS[index];
    const signIndex = index;
    const houseNumber = getHouseNumber(signIndex);
    const planetsInHouse = planetsByHouse[houseNumber] || [];

    const x = col * gridSize;
    const y = row * gridSize;

    // Cell border - thin
    svg += `<rect x="${x}" y="${y}" width="${gridSize}" height="${gridSize}" fill="none" stroke="${BROWN}" stroke-width="0.5"/>`;

    // Sign name + House number - combined (top)
    svg += `<text x="${x + 3}" y="${y + 8}" font-size="6" fill="${BROWN}" font-weight="bold" font-family="Arial">${ZODIAC_SIGNS_SHORT[signIndex]} ${houseNumber}</text>`;

    // Build render items: ASC first (if house 1), then planets
    let currentY = y + 14;
    const lineHeight = 6;
    
    // ASC with coordinates (house 1)
    if (houseNumber === 1) {
      const ascDegree = ascendantSign % 30;
      const ascDeg = Math.floor(ascDegree);
      const ascMin = Math.floor((ascDegree % 1) * 60);
      svg += `<text x="${x + 3}" y="${currentY}" font-size="5" fill="${BROWN}" font-family="Arial">ASC ${ascDeg}°${ascMin}'</text>`;
      currentY += lineHeight;
    }

    // Planets - show all, compact format
    planetsInHouse.forEach((planet) => {
      const suffix = planet.retrograde ? 'R' : '';
      svg += `<text x="${x + 3}" y="${currentY}" font-size="5" fill="${BLACK}" font-family="Arial">${getPlanetShort(planet.name)}${suffix}</text>`;
      currentY += lineHeight;
    });
  }

  svg += '</svg>';
  return svg;
}

/**
 * Convert SVG string to Base64 PNG data URL
 */
export async function svgToBase64PNG(svgString: string, size: number = 600): Promise<string> {
  return new Promise((resolve, reject) => {
    const canvas = document.createElement('canvas');
    const scale = 3; // High resolution
    canvas.width = size * scale;
    canvas.height = size * scale;
    const ctx = canvas.getContext('2d');
    
    if (!ctx) {
      reject(new Error('Cannot get canvas context'));
      return;
    }
    
    ctx.scale(scale, scale);
    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(0, 0, size, size);

    const img = new Image();
    const svgUrl = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svgString)}`;

    img.onload = () => {
      ctx.drawImage(img, 0, 0, size, size);
      const dataUrl = canvas.toDataURL('image/png', 1.0);
      resolve(dataUrl);
    };

    img.onerror = () => reject(new Error('Failed to load SVG'));
    img.crossOrigin = 'anonymous';
    img.src = svgUrl;
  });
}

/**
 * Generate all chart images for PDF
 */
export async function generatePDFChartImages(
  ascendant: number,
  planets: PdfPlanet[],
  houses: PdfHouse[],
  vargas: Array<{ id: string; planets: PdfVargaPlanet[]; ascendantSign: number }>
): Promise<{
  mainChartImage: string;
  vargaChartImages: Record<string, string>;
}> {
  // Debug: log vargas data
  console.log('generatePDFChartImages - vargas count:', vargas.length);
  vargas.forEach((v, i) => {
    console.log(`  varga[${i}]: id=${v.id}, planets=${v.planets.length}, ascendantSign=${v.ascendantSign}`);
  });

  // Generate main chart SVG
  const mainSvg = generateMainChartSVG(ascendant, planets, houses, 600);
  const mainChartImage = await svgToBase64PNG(mainSvg, 600);

  // Generate varga chart images in parallel
  const vargaPromises = vargas.map(async (varga, idx) => {
    console.log(`[${idx}] Generating SVG for ${varga.id}`);
    const vargaSvg = generateMiniChartSVG(varga.planets, varga.ascendantSign, 200);
    console.log(`[${idx}] Converting to PNG for ${varga.id}`);
    const vargaImage = await svgToBase64PNG(vargaSvg, 200);
    console.log(`[${idx}] Done ${varga.id}`);
    return { key: varga.id, image: vargaImage };
  });

  const vargaResults = await Promise.all(vargaPromises);
  console.log('vargaResults:', vargaResults.map(r => r.key));
  const vargaChartImages: Record<string, string> = {};
  vargaResults.forEach(({ key, image }) => {
    vargaChartImages[key] = image;
  });
  console.log('vargaChartImages keys:', Object.keys(vargaChartImages));

  return { mainChartImage, vargaChartImages };
}
